Here's a modern MSTest data-driven test example for your `PriceCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline test cases for CalculateTotal ---
    [TestMethod]
    [DataRow(10.0, 1, 10.0)]
    [DataRow(10.0, 3, 30.0)]
    [DataRow(0.0, 5, 0.0)]
    [DataRow(19.99, 2, 39.98)]
    public void CalculateTotal_ReturnsExpected(double price, int quantity, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)price, quantity);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DataRow: inline test cases for ApplyDiscount ---
    [TestMethod]
    [DataRow(100.0, 10.0, 90.0)]
    [DataRow(100.0, 0.0, 100.0)]
    [DataRow(50.0, 50.0, 25.0)]
    [DataRow(200.0, 100.0, 0.0)]
    public void ApplyDiscount_ReturnsExpected(double total, double discountPct, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)total, (decimal)discountPct);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: complex/reusable test cases from a method ---
    [TestMethod]
    [DynamicData(nameof(GetCalculateTotalEdgeCases), DynamicDataSourceType.Method)]
    public void CalculateTotal_EdgeCases(decimal price, int quantity, decimal expected)
    {
        var result = _calculator.CalculateTotal(price, quantity);
        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> GetCalculateTotalEdgeCases()
    {
        yield return new object[] { 0.01m, 1, 0.01m };
        yield return new object[] { 999.99m, 100, 99999.00m };
        yield return new object[] { 5.555m, 2, 11.11m };
    }

    // --- DynamicData: from a property ---
    [TestMethod]
    [DynamicData(nameof(DiscountEdgeCases), DynamicDataSourceType.Property)]
    public void ApplyDiscount_EdgeCases(decimal total, decimal discountPct, decimal expected)
    {
        var result = _calculator.ApplyDiscount(total, discountPct);
        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> DiscountEdgeCases => new[]
    {
        new object[] { 0m, 50m, 0m },
        new object[] { 1000m, 15.5m, 845.00m },
        new object[] { 49.99m, 25m, 37.4925m },
    };

    // --- Negative cases ---
    [TestMethod]
    [DataRow(-1.0, 1)]
    [DataRow(10.0, -1)]
    public void CalculateTotal_InvalidInput_Throws(double price, int quantity)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _calculator.CalculateTotal((decimal)price, quantity));
    }

    [TestMethod]
    [DataRow(100.0, -5.0)]
    [DataRow(100.0, 101.0)]
    public void ApplyDiscount_InvalidPercent_Throws(double total, double discountPct)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)total, (decimal)discountPct));
    }
}
```

**Key best practices shown:**

| Technique | When to use |
|-----------|------------|
| `[DataRow]` | Simple inline values (note: only primitives allowed) |
| `[DynamicData]` (method) | Complex types, computed values, or many cases |
| `[DynamicData]` (property) | Reusable datasets shared across tests |

**Notes:**
- `DataRow` only supports compile-time constants, so use `double` and cast to `decimal` inside the test.
- `DynamicData` accepts `decimal` directly since values come from code.
- Each `DataRow`/`DynamicData` entry runs as a separate test case in Test Explorer.
- Add `[DataRow(..., DisplayName = "...")]` for readable names in the runner.
